import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String input = scanner.nextLine();

        // Limiting the buffer size to prevent buffer overflow
        byte[] buffer = new byte[10];

        // Ensuring the input length does not exceed the buffer size
        int length = Math.min(input.length(), buffer.length);

        // Copying only up to the allowed length into the buffer
        System.arraycopy(input.getBytes(), 0, buffer, 0, length);

        System.out.println("Hello, " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
